 }
 return key;
}
// Function to encrypt a message using the key
string encrypt(string message, string key)
{
 string ciphertext = "";
 for (int i = 0; i < message.length(); i++)
 {
 // Convert the message character to uppercase
 char c = toupper(message[i]);
 // If the character is a letter, encrypt it using the key
 if (isalpha(c))
 {
 int index = c - 'A';
 ciphertext += key[index];
 }
 // If the character is not a letter, leave it as is
 else
 {
 ciphertext += c;
 }
 }
 return ciphertext;
}
// Function to decrypt a message using the key
string decrypt(string ciphertext, string key)
{
 string message = "";
 for (int i = 0; i < ciphertext.length(); i++)
 {
 // Convert the ciphertext character to uppercase
 char c = toupper(ciphertext[i]);
 // If the character is a letter, decrypt it using the key
 if (isalpha(c))
 {
 int index = key.find(c);
 message += 'A' + index;
 }
 // If the character is not a letter, leave it as is
 else
 {
 message += c;
 }
 }
 return message;
}
